CREATE EXTENSION IF NOT EXISTS "uuid-ossp";

CREATE TABLE IF NOT EXISTS learner_workspaces (id uuid PRIMARY KEY DEFAULT uuid_generate_v4(), display_name text NOT NULL, owner_identity text NOT NULL UNIQUE, privacy_state text NOT NULL DEFAULT 'private', created_at timestamptz NOT NULL DEFAULT now(), updated_at timestamptz NOT NULL DEFAULT now(), archived_at timestamptz);
CREATE TABLE IF NOT EXISTS learner_preferences (id uuid PRIMARY KEY DEFAULT uuid_generate_v4(), learner_workspace_id uuid NOT NULL REFERENCES learner_workspaces(id), daily_capacity_default integer NOT NULL DEFAULT 20, review_grading_style text NOT NULL DEFAULT 'confidence', timezone text NOT NULL DEFAULT 'UTC', visual_theme_palette_id text NOT NULL DEFAULT 'soft-study', created_at timestamptz NOT NULL DEFAULT now(), updated_at timestamptz NOT NULL DEFAULT now(), archived_at timestamptz);
CREATE TABLE IF NOT EXISTS visual_theme_palettes (id text PRIMARY KEY, name text NOT NULL, primary_background text NOT NULL, accent_background_1 text NOT NULL, accent_background_2 text NOT NULL, semantic_warning_color text NOT NULL, semantic_error_color text NOT NULL, semantic_success_color text NOT NULL, readability_notes text NOT NULL);
INSERT INTO visual_theme_palettes(id,name,primary_background,accent_background_1,accent_background_2,semantic_warning_color,semantic_error_color,semantic_success_color,readability_notes) VALUES ('soft-study','Soft Study','#fff8e7','#f8e7ff','#e7fff8','#8a5a00','#b42318','#027a48','Readable text, controls, charts, focus indicators, and state labels on all palette backgrounds.') ON CONFLICT (id) DO NOTHING;
CREATE TABLE IF NOT EXISTS tags (id uuid PRIMARY KEY DEFAULT uuid_generate_v4(), learner_workspace_id uuid NOT NULL REFERENCES learner_workspaces(id), name text NOT NULL, color text, description text, created_at timestamptz NOT NULL DEFAULT now(), updated_at timestamptz NOT NULL DEFAULT now(), archived_at timestamptz, UNIQUE(learner_workspace_id, lower(name)));
CREATE TABLE IF NOT EXISTS source_materials (id uuid PRIMARY KEY DEFAULT uuid_generate_v4(), learner_workspace_id uuid NOT NULL REFERENCES learner_workspaces(id), source_type text NOT NULL, title text NOT NULL, original_location text, content_digest text, content_summary text, content_status text NOT NULL DEFAULT 'available', processing_status text NOT NULL DEFAULT 'draft', failure_reason text, duplicate_status text NOT NULL DEFAULT 'unchecked', current_version_id uuid, created_at timestamptz NOT NULL DEFAULT now(), updated_at timestamptz NOT NULL DEFAULT now(), archived_at timestamptz);
CREATE TABLE IF NOT EXISTS material_versions (id uuid PRIMARY KEY DEFAULT uuid_generate_v4(), source_material_id uuid NOT NULL REFERENCES source_materials(id), version_number integer NOT NULL, content_digest text NOT NULL, content_location text, summary text, created_by_action text NOT NULL, created_at timestamptz NOT NULL DEFAULT now(), updated_at timestamptz NOT NULL DEFAULT now(), archived_at timestamptz, UNIQUE(source_material_id, version_number));
CREATE TABLE IF NOT EXISTS knowledge_points (id uuid PRIMARY KEY DEFAULT uuid_generate_v4(), learner_workspace_id uuid NOT NULL REFERENCES learner_workspaces(id), source_material_id uuid REFERENCES source_materials(id), material_version_id uuid REFERENCES material_versions(id), content text NOT NULL, summary text, notes text, approval_status text NOT NULL DEFAULT 'draft', creation_source text NOT NULL DEFAULT 'ai_generated', duplicate_group_id uuid, graph_label text, graph_position_hint text, ai_job_id uuid, prompt_snapshot_id uuid, approved_at timestamptz, rejected_at timestamptz, created_at timestamptz NOT NULL DEFAULT now(), updated_at timestamptz NOT NULL DEFAULT now(), archived_at timestamptz);
CREATE TABLE IF NOT EXISTS knowledge_relationships (id uuid PRIMARY KEY DEFAULT uuid_generate_v4(), learner_workspace_id uuid NOT NULL REFERENCES learner_workspaces(id), source_knowledge_point_id uuid REFERENCES knowledge_points(id), target_knowledge_point_id uuid REFERENCES knowledge_points(id), relationship_type text NOT NULL, label text, weight numeric NOT NULL DEFAULT 1, source_type text NOT NULL DEFAULT 'system_derived', source_material_id uuid REFERENCES source_materials(id), tag_id uuid REFERENCES tags(id), card_id uuid, confidence numeric, created_at timestamptz NOT NULL DEFAULT now(), updated_at timestamptz NOT NULL DEFAULT now(), archived_at timestamptz);
CREATE INDEX IF NOT EXISTS idx_knowledge_relationships_workspace_type ON knowledge_relationships(learner_workspace_id, relationship_type);
CREATE INDEX IF NOT EXISTS idx_knowledge_relationships_source_target ON knowledge_relationships(source_knowledge_point_id, target_knowledge_point_id);
CREATE TABLE IF NOT EXISTS prompt_presets (id uuid PRIMARY KEY DEFAULT uuid_generate_v4(), learner_workspace_id uuid NOT NULL REFERENCES learner_workspaces(id), name text NOT NULL, purpose text NOT NULL, prompt_text text NOT NULL, is_default boolean NOT NULL DEFAULT false, version_number integer NOT NULL DEFAULT 1, created_at timestamptz NOT NULL DEFAULT now(), updated_at timestamptz NOT NULL DEFAULT now(), archived_at timestamptz);
CREATE TABLE IF NOT EXISTS prompt_snapshots (id uuid PRIMARY KEY DEFAULT uuid_generate_v4(), prompt_preset_id uuid REFERENCES prompt_presets(id), purpose text NOT NULL, prompt_text text NOT NULL, model_id text NOT NULL, schema_version text NOT NULL, created_for_job_id uuid, created_at timestamptz NOT NULL DEFAULT now(), updated_at timestamptz NOT NULL DEFAULT now(), archived_at timestamptz);
CREATE TABLE IF NOT EXISTS ai_jobs (id uuid PRIMARY KEY DEFAULT uuid_generate_v4(), learner_workspace_id uuid NOT NULL REFERENCES learner_workspaces(id), job_type text NOT NULL, status text NOT NULL DEFAULT 'queued', progress_percent integer NOT NULL DEFAULT 0, current_step text NOT NULL DEFAULT 'queued', input_summary text, error_category text, error_message text, idempotency_key text, started_at timestamptz, finished_at timestamptz, created_at timestamptz NOT NULL DEFAULT now(), updated_at timestamptz NOT NULL DEFAULT now(), archived_at timestamptz);
CREATE TABLE IF NOT EXISTS ai_drafts (id uuid PRIMARY KEY DEFAULT uuid_generate_v4(), learner_workspace_id uuid NOT NULL REFERENCES learner_workspaces(id), draft_type text NOT NULL, job_id uuid REFERENCES ai_jobs(id), payload jsonb NOT NULL DEFAULT '{}', validation_status text NOT NULL DEFAULT 'valid', validation_messages jsonb NOT NULL DEFAULT '[]', status text NOT NULL DEFAULT 'draft', approved_record_id uuid, created_at timestamptz NOT NULL DEFAULT now(), updated_at timestamptz NOT NULL DEFAULT now(), archived_at timestamptz);
CREATE TABLE IF NOT EXISTS decks (id uuid PRIMARY KEY DEFAULT uuid_generate_v4(), learner_workspace_id uuid NOT NULL REFERENCES learner_workspaces(id), name text NOT NULL, description text, creation_source text NOT NULL DEFAULT 'manual', status text NOT NULL DEFAULT 'active', ai_job_id uuid, prompt_snapshot_id uuid, created_at timestamptz NOT NULL DEFAULT now(), updated_at timestamptz NOT NULL DEFAULT now(), archived_at timestamptz);
CREATE TABLE IF NOT EXISTS cards (id uuid PRIMARY KEY DEFAULT uuid_generate_v4(), learner_workspace_id uuid NOT NULL REFERENCES learner_workspaces(id), front_prompt text NOT NULL, back_answer text NOT NULL, explanation text, learner_notes text, difficulty text NOT NULL DEFAULT 'unrated', creation_source text NOT NULL DEFAULT 'manual', status text NOT NULL DEFAULT 'draft', review_status text NOT NULL DEFAULT 'new', ai_job_id uuid, prompt_snapshot_id uuid, created_at timestamptz NOT NULL DEFAULT now(), updated_at timestamptz NOT NULL DEFAULT now(), archived_at timestamptz);
CREATE TABLE IF NOT EXISTS review_sessions (id uuid PRIMARY KEY DEFAULT uuid_generate_v4(), learner_workspace_id uuid NOT NULL REFERENCES learner_workspaces(id), session_type text NOT NULL, deck_id uuid, review_plan_id uuid, status text NOT NULL DEFAULT 'active', started_at timestamptz NOT NULL DEFAULT now(), paused_at timestamptz, completed_at timestamptz, summary text, created_at timestamptz NOT NULL DEFAULT now(), updated_at timestamptz NOT NULL DEFAULT now(), archived_at timestamptz);
CREATE TABLE IF NOT EXISTS review_plans (id uuid PRIMARY KEY DEFAULT uuid_generate_v4(), learner_workspace_id uuid NOT NULL REFERENCES learner_workspaces(id), name text NOT NULL, goal text, start_date date, target_completion_date date, daily_capacity integer NOT NULL, status text NOT NULL DEFAULT 'draft', overlap_policy text NOT NULL DEFAULT 'prevent', current_revision_id uuid, created_at timestamptz NOT NULL DEFAULT now(), updated_at timestamptz NOT NULL DEFAULT now(), archived_at timestamptz);
CREATE TABLE IF NOT EXISTS review_statistics_snapshots (id uuid PRIMARY KEY DEFAULT uuid_generate_v4(), learner_workspace_id uuid NOT NULL REFERENCES learner_workspaces(id), scope_type text NOT NULL, scope_id uuid, period_start date NOT NULL, period_end date NOT NULL, cards_reviewed integer NOT NULL DEFAULT 0, recall_rate numeric NOT NULL DEFAULT 0, overdue_count integer NOT NULL DEFAULT 0, completion_rate numeric NOT NULL DEFAULT 0, weak_area_score numeric NOT NULL DEFAULT 0, generated_at timestamptz NOT NULL DEFAULT now());
CREATE TABLE IF NOT EXISTS workspace_exports (id uuid PRIMARY KEY DEFAULT uuid_generate_v4(), learner_workspace_id uuid NOT NULL REFERENCES learner_workspaces(id), status text NOT NULL DEFAULT 'queued', included_content jsonb NOT NULL DEFAULT '[]', file_location text, expires_at timestamptz, failure_reason text, created_at timestamptz NOT NULL DEFAULT now(), updated_at timestamptz NOT NULL DEFAULT now(), archived_at timestamptz);
